import{_ as t,o as h,c as o,ag as a}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Bảng Playbook Ứng Dụng (Use Cases) Cho Boxme","description":"","frontmatter":{},"headers":[],"relativePath":"playbook.md","filePath":"playbook.md"}'),i={name:"playbook.md"};function e(g,n,c,l,r,s){return h(),o("div",null,[...n[0]||(n[0]=[a('<h1 id="bang-playbook-ung-dung-use-cases-cho-boxme" tabindex="-1">Bảng Playbook Ứng Dụng (Use Cases) Cho Boxme <a class="header-anchor" href="#bang-playbook-ung-dung-use-cases-cho-boxme" aria-label="Permalink to &quot;Bảng Playbook Ứng Dụng (Use Cases) Cho Boxme&quot;">​</a></h1><p>Happy Agent (Cỗ máy Tự động hoá vạn năng) không chỉ dùng cho TikTok mà có thể triển khai tự động hóa cho nhiều bộ phận khác nhau trong nội bộ Boxme, giúp nhân sự thao tác tự động, không tốn Token phụ phí nhờ mô hình Local CLI (Opencode / Gemini CLI).</p><p>Dưới đây là các <strong>Use Case (SOP)</strong> gợi ý để đào tạo (Dạy Skill) cho Happy Agent tuỳ theo đặc thù từng phòng ban:</p><h2 id="_1-phong-nhan-su-hr" tabindex="-1">1. Phòng Nhân sự (HR) <a class="header-anchor" href="#_1-phong-nhan-su-hr" aria-label="Permalink to &quot;1. Phòng Nhân sự (HR)&quot;">​</a></h2><ul><li><strong>Tự động đăng tin tuyển dụng đa kênh:</strong> Lấy nội dung từ Google Docs/Notion, tự động mở các trang tuyển dụng (TopCV, VietnamWorks, LinkedIn), copy-paste, chọn danh mục và đẩy tin tự động.</li><li><strong>Onboarding Nhân viên mới:</strong> Tự động hoá việc gửi email thông báo, tự click mời tài khoản vào hệ thống Slack, Jira, Bitbucket sau khi có email nhân sự từ File Excel trúng tuyển.</li><li><strong>Lọc CV hàng loạt:</strong> Mở list CV từ Drive, trích xuất dữ liệu cơ bản (Tên, Số Đt, Kỹ năng) và copy tự động vào bảng Google Sheets quản lý Ứng viên.</li></ul><h2 id="_2-ke-toan-tai-chinh-finance-accounting" tabindex="-1">2. Kế toán &amp; Tài chính (Finance / Accounting) <a class="header-anchor" href="#_2-ke-toan-tai-chinh-finance-accounting" aria-label="Permalink to &quot;2. Kế toán &amp; Tài chính (Finance / Accounting)&quot;">​</a></h2><ul><li><strong>Cào dữ liệu tỷ giá &amp; Lãi suất:</strong> Mỗi sáng tự động mở trang web ngân hàng, copy tỷ giá USD/VND hiện tại và điền vào phần mềm kế toán hoặc nhóm Slack báo cáo.</li><li><strong>Tải hoá đơn đỏ tự động:</strong> Đăng nhập vào các cổng xuất hoá đơn điện tử của nhà cung cấp, tải file PDF/XML về thư mục lưu trữ cục bộ theo đúng cấu trúc Ngày-Tháng.</li><li><strong>Đối soát sao kê tĩnh:</strong> Lấy báo cáo từ Excel Cổng thanh toán, tự mở phần mềm ERP nội bộ khớp lệnh các khoản tiền thu về.</li></ul><h2 id="_3-mua-hang-purchasing" tabindex="-1">3. Mua hàng (Purchasing) <a class="header-anchor" href="#_3-mua-hang-purchasing" aria-label="Permalink to &quot;3. Mua hàng (Purchasing)&quot;">​</a></h2><ul><li><strong>Theo dõi giá Nhà Cung cấp (Scraping):</strong> Tự động cào giá và số lượng tồn kho của các sản phẩm trên trang web nguồn (Taobao, 1688, Shopee) và cảnh báo khi giá vượt ngưỡng quy định.</li><li><strong>Tự động đặt lại vật tư:</strong> Nếu trong sheet quy định số lượng băng dính/thùng carton dưới mức tối thiểu, Agent tự động đăng nhập trang B2B nhà cung cấp và đặt hàng chờ duyệt.</li></ul><h2 id="_4-ho-tro-khach-hang-customer-support" tabindex="-1">4. Hỗ trợ Khách hàng (Customer Support) <a class="header-anchor" href="#_4-ho-tro-khach-hang-customer-support" aria-label="Permalink to &quot;4. Hỗ trợ Khách hàng (Customer Support)&quot;">​</a></h2><ul><li><strong>Auto-Reply Ticket:</strong> Quét tài khoản kênh đánh giá/khiếu nại, lấy mẫu câu trả lời phù hợp trong <code>message-template.json</code> và trả lời hàng loạt các khiếu nại tương đồng (vd. lỗi giao hàng chậm).</li><li><strong>Trích xuất thông tin ID Đơn Hàng:</strong> Tự vào hệ thống Zalo OA, nếu thấy KH nhắn mã đơn hàng, Agent tự mở trang Admin ERP lấy trạng thái đơn gửi về lại cho KH.</li><li><strong>Xin đánh giá:</strong> Nhắn tin tự động xin review 5 sao hoặc phản hồi khách hàng thông qua kênh Shopee Chat/Tiktok Chat sau khi giao hàng thành công.</li></ul><h2 id="_5-kinh-doanh-sales-bd" tabindex="-1">5. Kinh doanh (Sales / BD) <a class="header-anchor" href="#_5-kinh-doanh-sales-bd" aria-label="Permalink to &quot;5. Kinh doanh (Sales / BD)&quot;">​</a></h2><ul><li><strong>Cào File Đối tác tiềm năng (Lead Generation):</strong> Vào các nhóm Facebook kinh doanh / Top seller Shopee, quét tên cửa hàng, số điện thoại hoặc email rồi cập nhật vào CRM của công ty.</li><li><strong>Rải tin nhắn Mời lên sàn:</strong> (Giống tính năng cốt lõi Tiktok Invite hiện tại). Tự động rải hàng loạt tin nhắn mời hợp tác cho các Influencers/KOCs theo kịch bản cá nhân hoá dựa trên ngách của họ.</li></ul><h2 id="_6-cong-nghe-ky-thuat-tech-it" tabindex="-1">6. Công nghệ / Kỹ thuật (Tech / IT) <a class="header-anchor" href="#_6-cong-nghe-ky-thuat-tech-it" aria-label="Permalink to &quot;6. Công nghệ / Kỹ thuật (Tech / IT)&quot;">​</a></h2><ul><li><strong>Tạo Account Nội bộ hàng loạt:</strong> Tự động điền Form cấu trúc để cấp phát quyền (Jira, Confluence, Email) khi có nhân viên mới or tắt tài khoản cho người vừa nghỉ chỉ từ 1 click file CSV.</li><li><strong>Cronjob theo dõi Hệ thống Health Check:</strong> Tự động mở Dashboard theo dõi log rớt đơn, nếu có lỗi bất thường Agent tự chụp ảnh màn hình nén lại gửi cảnh báo qua Telegram.</li></ul><h2 id="_7-doanh-thu-cong-no-revenue-cashflow" tabindex="-1">7. Doanh thu &amp; Công nợ (Revenue / Cashflow) <a class="header-anchor" href="#_7-doanh-thu-cong-no-revenue-cashflow" aria-label="Permalink to &quot;7. Doanh thu &amp; Công nợ (Revenue / Cashflow)&quot;">​</a></h2><ul><li><strong>Nhắc nợ tự động:</strong> Dựa vào danh sách công nợ trên sheet, Agent tự động lấy chi tiết, login vào email/Zalo gửi tin nhắn nhắc nhở quá hạn thanh toán đối với các tập KH trả sau của Boxme.</li><li><strong>Báo cáo Tiền về đa sàn:</strong> Buổi tối Agent login vào Seller Center 3 sàn (Tiktok, Shopee, Lazada) tổng hợp số tiền đối soát chuẩn bị chuyển về tài khoản, ném vào Group BOT Telegram.</li></ul><h2 id="_8-kho-van-fulfillment-operations" tabindex="-1">8. Kho vận (Fulfillment / Operations) <a class="header-anchor" href="#_8-kho-van-fulfillment-operations" aria-label="Permalink to &quot;8. Kho vận (Fulfillment / Operations)&quot;">​</a></h2><ul><li><strong>Phân tệp Nhãn dán:</strong> Tự động tải hàng ngàn tem vận đơn PDF từ Seller Center, phân chia thành các thư mục nhỏ để máy in in dần theo kịch bản không bị nghẽn mạng máy in nội bộ.</li><li><strong>Theo dõi Đơn Lỗi/Hoàn:</strong> Tự động phân loại đơn hàng rớt/hỏng/hoàn trên Dashboard để kho lập tức xuất quy trình liên lạc lại tránh phạt giao trễ.</li></ul><hr><h3 id="huong-dan-cach-day-teach-skill-cac-playbook-nay" tabindex="-1">Hướng dẫn cách &quot;Dạy&quot; (Teach Skill) các Playbook này <a class="header-anchor" href="#huong-dan-cach-day-teach-skill-cac-playbook-nay" aria-label="Permalink to &quot;Hướng dẫn cách &quot;Dạy&quot; (Teach Skill) các Playbook này&quot;">​</a></h3><ol><li><strong>Chuẩn bị SOP Mẫu</strong>: Các phòng ban chỉ cần làm thao tác chuẩn (Bấm đâu, Gõ gì) 1 lần, quay video hoặc xuất dưới dạng chữ.</li><li><strong>Kéo thả File vào Táp &quot;Dạy Skill&quot;</strong>: Mở giao diện Light Mode -&gt; Upload lên.</li><li>Happy Agent với sức mạnh của Local AI CLI (như Gemini) sẽ học lệnh và tự động biến thành kỹ năng vận hành vĩnh viễn. Không tốn tiền duy trì, bảo mật tuyệt đối 100% dữ liệu vì mọi thứ chạy trên máy tính nội bộ của phòng ban (Localhost).</li></ol>',22)])])}const d=t(i,[["render",e]]);export{p as __pageData,d as default};
